def verify(subject: str, predicate: str, obj: str) -> bool:
    # This function verifies if the subject number is prime when predicate is 'is_prime'.
    # It returns True if the primality matches the object value ('true'/'false'), False otherwise.

    if predicate != 'is_prime':
        return False

    try:
        n = int(subject)
    except ValueError:
        return False

    if obj.lower() not in ('true', 'false'):
        return False

    def is_prime(num: int) -> bool:
        if num <= 1:
            return False
        if num <= 3:
            return True
        if num % 2 == 0 or num % 3 == 0:
            return False
        i = 5
        while i * i <= num:
            if num % i == 0 or num % (i + 2) == 0:
                return False
            i += 6
        return True

    primality = is_prime(n)
    expected = obj.lower() == 'true'
    return primality == expected

